import os
from datetime import datetime
from typing import Optional

from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from sqlalchemy import Column, DateTime, Integer, String, create_engine, func
from sqlalchemy.ext.asyncio import AsyncSession, create_async_engine
from sqlalchemy.orm import declarative_base, sessionmaker
from sqlalchemy.future import select

import uvicorn

# ---------- 数据库配置 ----------
DATABASE_URL = "sqlite+aiosqlite:///./tasks.db"

engine = create_async_engine(DATABASE_URL, echo=False)
async_session = sessionmaker(engine, class_=AsyncSession, expire_on_commit=False)

Base = declarative_base()


# ---------- 任务模型 ----------
class TaskModel(Base):
    __tablename__ = "tasks"

    id = Column(Integer, primary_key=True, autoincrement=True)
    title = Column(String(200), nullable=False)
    description = Column(String(1000), default="")
    status = Column(String(20), default="待办")
    created_at = Column(DateTime, default=func.now())
    updated_at = Column(DateTime, default=func.now(), onupdate=func.now())


# ---------- Pydantic 模型 ----------
class TaskCreate(BaseModel):
    title: str
    description: Optional[str] = ""
    status: Optional[str] = "待办"


class TaskUpdate(BaseModel):
    title: Optional[str] = None
    description: Optional[str] = None
    status: Optional[str] = None


class TaskResponse(BaseModel):
    id: int
    title: str
    description: str
    status: str
    created_at: str
    updated_at: str

    class Config:
        from_attributes = True


# ---------- FastAPI 应用 ----------
app = FastAPI(title="任务管理系统")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)


# ---------- 初始化数据库表 ----------
@app.on_event("startup")
async def startup():
    async with engine.begin() as conn:
        await conn.run_sync(Base.metadata.create_all)


# ---------- API 路由 ----------
@app.get("/tasks", response_model=list[TaskResponse])
async def get_tasks():
    async with async_session() as session:
        result = await session.execute(select(TaskModel).order_by(TaskModel.created_at.desc()))
        tasks = result.scalars().all()
        return [
            TaskResponse(
                id=t.id,
                title=t.title,
                description=t.description or "",
                status=t.status,
                created_at=t.created_at.strftime("%Y-%m-%d %H:%M:%S") if t.created_at else "",
                updated_at=t.updated_at.strftime("%Y-%m-%d %H:%M:%S") if t.updated_at else "",
            )
            for t in tasks
        ]


@app.post("/tasks", response_model=TaskResponse)
async def create_task(task: TaskCreate):
    async with async_session() as session:
        new_task = TaskModel(
            title=task.title,
            description=task.description or "",
            status=task.status or "待办",
        )
        session.add(new_task)
        await session.commit()
        await session.refresh(new_task)
        return TaskResponse(
            id=new_task.id,
            title=new_task.title,
            description=new_task.description or "",
            status=new_task.status,
            created_at=new_task.created_at.strftime("%Y-%m-%d %H:%M:%S") if new_task.created_at else "",
            updated_at=new_task.updated_at.strftime("%Y-%m-%d %H:%M:%S") if new_task.updated_at else "",
        )


@app.get("/tasks/{task_id}", response_model=TaskResponse)
async def get_task(task_id: int):
    async with async_session() as session:
        result = await session.execute(select(TaskModel).where(TaskModel.id == task_id))
        task = result.scalar_one_or_none()
        if not task:
            raise HTTPException(status_code=404, detail="任务不存在")
        return TaskResponse(
            id=task.id,
            title=task.title,
            description=task.description or "",
            status=task.status,
            created_at=task.created_at.strftime("%Y-%m-%d %H:%M:%S") if task.created_at else "",
            updated_at=task.updated_at.strftime("%Y-%m-%d %H:%M:%S") if task.updated_at else "",
        )


@app.put("/tasks/{task_id}", response_model=TaskResponse)
async def update_task(task_id: int, task: TaskUpdate):
    async with async_session() as session:
        result = await session.execute(select(TaskModel).where(TaskModel.id == task_id))
        db_task = result.scalar_one_or_none()
        if not db_task:
            raise HTTPException(status_code=404, detail="任务不存在")

        if task.title is not None:
            db_task.title = task.title
        if task.description is not None:
            db_task.description = task.description
        if task.status is not None:
            db_task.status = task.status
        db_task.updated_at = datetime.utcnow()

        await session.commit()
        await session.refresh(db_task)
        return TaskResponse(
            id=db_task.id,
            title=db_task.title,
            description=db_task.description or "",
            status=db_task.status,
            created_at=db_task.created_at.strftime("%Y-%m-%d %H:%M:%S") if db_task.created_at else "",
            updated_at=db_task.updated_at.strftime("%Y-%m-%d %H:%M:%S") if db_task.updated_at else "",
        )


@app.delete("/tasks/{task_id}", response_model=dict)
async def delete_task(task_id: int):
    async with async_session() as session:
        result = await session.execute(select(TaskModel).where(TaskModel.id == task_id))
        task = result.scalar_one_or_none()
        if not task:
            raise HTTPException(status_code=404, detail="任务不存在")
        await session.delete(task)
        await session.commit()
        return {"message": "任务已删除", "id": task_id}


# ---------- 启动 ----------
if __name__ == "__main__":
    uvicorn.run("task_manager_api:app", host="127.0.0.1", port=8000, reload=True)
```

