            card.dataset.status = task.status;

            const statusClass = getStatusClass(task.status);

            card.innerHTML = `
                <div class="task-header">
                    <div class="task-title" id="title-display-${task.id}">
                        ${escapeHtml(task.title)}
                    </div>
                    <div class="task-actions">
                        <button class="btn btn-sm btn-edit" onclick="startEdit(${task.id})">✏️ 编辑</button>
                        <button class="btn btn-sm btn-delete" onclick="confirmDelete(${task.id})">🗑️ 删除</button>
                    </div>
                </div>
                <div class="task-desc" id="desc-display-${task.id}">
                    ${task.description ? escapeHtml(task.description) : '<span style="color:#cbd5e1">暂无描述</span>'}
                </div>
                <div class="task-footer">
                    <div class="task-meta">
                        <span class="status-badge ${statusClass}" onclick="cycleStatus(${task.id})" title="点击切换状态">
                            ${task.status}
                        </span>
                        <span class="task-time">${task.created_at}</span>
                    </div>
                </div>
                <!-- 编辑区域（隐藏） -->
                <div id="edit-area-${task.id}" style="display:none; margin-top:8px;">
                    <div class="form-group" style="margin-bottom:8px;">
                        <label style="font-size:0.8rem;color:var(--text-light);">标题</label>
                        <input type="text" id="edit-title-${task.id}" value="${escapeHtml(task.title)}" style="width:100%;padding:8px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:0.95rem;" />
                    </div>
                    <div class="form-group" style="margin-bottom:8px;">
                        <label style="font-size:0.8rem;color:var(--text-light);">描述</label>
                        <textarea id="edit-desc-${task.id}" rows="2" style="width:100%;padding:8px 12px;border:1.5px solid var(--border);border-radius:8px;font-size:0.9rem;font-family:inherit;resize:vertical;">${escapeHtml(task.description || '')}</textarea>
                    </div>
                    <div class="edit-actions">
                        <button class="btn btn-sm btn-save" onclick="saveEdit(${task.id})">💾 保存</button>
                        <button class="btn btn-sm btn-cancel" onclick="cancelEdit(${task.id})">取消</button>
                    </div>
                </div>
            `;

            return card;
        }

        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        function renderTaskList(tasks) {
            const container = document.getElementById('taskList');
            const count = document.getElementById('taskCount');

            if (!tasks || tasks.length === 0) {
                container.innerHTML = `
                    <div class="empty-state">
                        <div class="icon">📭</div>
                        <p>暂无任务，快来添加一个吧！</p>
                    </div>
                `;
                count.textContent = '0';
                return;
            }

            container.innerHTML = '';
            tasks.forEach(task => {
                container.appendChild(renderTaskCard(task));
            });
            count.textContent = tasks.length;
        }

        function updateStats(tasks) {
            const total = tasks.length;
            const todo = tasks.filter(t => t.status === '待办').length;
            const progress = tasks.filter(t => t.status === '进行中').length;
            const done = tasks.filter(t => t.status === '已完成').length;

            document.getElementById('totalCount').textContent = total;
            document.getElementById('todoCount').textContent = todo;
            document.getElementById('progressCount').textContent = progress;
            document.getElementById('doneCount').textContent = done;
        }

        // ============================================================
        // 加载任务
        // ============================================================
        async function loadTasks() {
            const container = document.getElementById('taskList');
            container.innerHTML = '<div class="loading"><div class="spinner"></div><p style="margin-top:10px;">加载中...</p></div>';

            try {
                const tasks = await fetchTasks();
                renderTaskList(tasks);
                updateStats(tasks);
            } catch (err) {
                container.innerHTML = `
                    <div class="empty-state">
                        <div class="icon">⚠️</div>
                        <p>加载失败：${err.message}</p>
                        <button class="btn btn-primary btn-sm" style="margin-top:12px;" onclick="loadTasks()">🔄 重试</button>
                    </div>
                `;
                showToast('加载任务失败：' + err.message, 'error');
            }
        }

        // ============================================================
        // 创建任务
        // ============================================================
        document.getElementById('taskForm').addEventListener('submit', async (e) => {
            e.preventDefault();

            const title = document.getElementById('title').value.trim();
            const description = document.getElementById('description').value.trim();
            const status = document.getElementById('statusSelect').value;

            if (!title) {
                showToast('请输入任务标题', 'error');
                return;
            }

            try {
                await createTask({ title, description, status });
                showToast('✅ 任务创建成功！', 'success');
                document.getElementById('taskForm').reset();
                await loadTasks();
            } catch (err) {
                showToast('创建失败：' + err.message, 'error');
            }
        });

        // ============================================================
        // 状态切换
        // ============================================================
        async function cycleStatus(id) {
            try {
                const tasks = await fetchTasks();
                const task = tasks.find(t => t.id === id);
                if (!task) return;

                const newStatus = STATUS_CYCLE[task.status] || '待办';
                await updateTask(id, { status: newStatus });
                showToast(`状态已切换为「${newStatus}」`, 'success');
                await loadTasks();
            } catch (err) {
                showToast('状态切换失败：' + err.message, 'error');
            }
        }

        // ============================================================
        // 删除
        // ============================================================
        async function confirmDelete(id) {
            if (!confirm('确定要删除这个任务吗？')) return;
            try {
                await deleteTask(id);
                showToast('🗑️ 任务已删除', 'success');
                await loadTasks();
            } catch (err) {
                showToast('删除失败：' + err.message, 'error');
            }
        }

        // ============================================================
        // 编辑
        // ============================================================
        let editingId = null;

        function startEdit(id) {
            if (editingId && editingId !== id) {
                cancelEdit(editingId);
            }

            editingId = id;

            // 隐藏显示区
            document.getElementById(`title-display-${id}`).style.display = 'none';
            document.getElementById(`desc-display-${id}`).style.display = 'none';
            // 显示编辑区
            document.getElementById(`edit-area-${id}`).style.display = 'block';

            // 隐藏操作按钮（编辑/删除）
            const actions = document.querySelector(`.task-card[data-id="${id}"] .task-actions`);
            if (actions) actions.style.display = 'none';
        }

        async function saveEdit(id) {
            const title = document.getElementById(`edit-title-${id}`).value.trim();
            const description = document.getElementById(`edit-desc-${id}`).value.trim();

            if (!title) {
                showToast('标题不能为空', 'error');
                return;
            }

            try {
                await updateTask(id, { title, description });
                showToast('💾 修改已保存！', 'success');
                cancelEdit(id);
                await loadTasks();
            } catch (err) {
                showToast('保存失败：' + err.message, 'error');
            }
        }

        function cancelEdit(id) {
            editingId = null;

            document.getElementById(`title-display-${id}`).style.display = '';
            document.getElementById(`desc-display-${id}`).style.display = '';
            document.getElementById(`edit-area-${id}`).style.display = 'none';

            const actions = document.querySelector(`.task-card[data-id="${id}"] .task-actions`);
            if (actions) actions.style.display = '';
        }

        // ============================================================
        // 初始化
        // ============================================================
        document.addEventListener('DOMContentLoaded', () => {
            loadTasks();
        });
    </script>
</body>
</html>
